import scala.math.BigInt

def solve(nums: Array[Long], maxC: Long): Long = {
    val n = nums.length
    var low = 1L
    var high = n.toLong
    var answer = 0L

    def computeGcd(left: Int, right: Int): Long = {
        var currentGcd = BigInt(nums(left))
        for (i <- left + 1 to right) {
            currentGcd = currentGcd.gcd(BigInt(nums(i)))
            if (currentGcd < 2) return currentGcd.toLong
        }
        currentGcd.toLong
    }

    while (low <= high) {
        val mid = (low + high) / 2
        var found = false

        for (i <- 0 to (n - mid.toInt)) {
            val j = i + mid.toInt - 1
            val currentGcd = computeGcd(i, j)
            if (currentGcd >= 2) {
                if (mid - 1 > maxC) {
                    found = true
                }
            }
        }

        if (found) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    if (answer == 0) {
        if (nums.exists(_ >= 2)) 1L else 0L
    } else {
        answer - 1
    }
}
